mapper.select:
SELECT
	SUM(TON)
FROM
	S_PORT_THROIGHPUT
WHERE CARGO_TYPE = #{cargoType}

	AND PORT_CODE = #{portCode}

AND TO_CHAR (DATE_TIME, 'YYYY') = #{dateTime}
AND DATE_TYPE = '1'

SELECT
	SUM(TON)
FROM
	S_PORT_THROIGHPUT
WHERE CARGO_TYPE = #{cargoType}

	AND PORT_CODE = #{portCode}

AND TO_CHAR (DATE_TIME, 'YYYY-MM') >= #{startTime}
AND TO_CHAR (DATE_TIME, 'YYYY-MM') <= #{endTime}
AND DATE_TYPE = '2'

SELECT
SUM(TON)
FROM
	S_PORT_THROIGHPUT
WHERE CARGO_TYPE = #{cargoType}

	AND PORT_CODE = #{portCode}

AND TO_CHAR (DATE_TIME, 'YYYY-MM') = #{dateTime}
AND DATE_TYPE = '2'

SELECT
	SUM(TON)
FROM
	S_PORT_THROIGHPUT
WHERE CARGO_TYPE = #{cargoType}

	AND PORT_CODE = #{portCode}

AND TO_CHAR (DATE_TIME, 'YYYY-MM-DD') = #{dateTime}
AND DATE_TYPE = '3'

SELECT TRUNC("SUM" (TON)) "ton", TO_CHAR (CREATE_TIME, 'YYYY-MM') "month" FROM ( SELECT "ABS" (TON) "TON", CREATE_TIME "CREATE_TIME" FROM T_PRD_PORT_STORAGE_DETAIL WHERE TO_CHAR (CREATE_TIME, 'YYYY-MM') IN
#{month}
) GROUP BY TO_CHAR (CREATE_TIME, 'YYYY-MM') ORDER BY TO_CHAR (CREATE_TIME, 'YYYY-MM')

SELECT TRUNC("SUM" (TON)) "ton", TO_CHAR (CREATE_TIME, 'YYYY-MM-DD') "day" FROM ( SELECT "ABS" (TON) "TON", CREATE_TIME "CREATE_TIME" FROM T_PRD_PORT_STORAGE_DETAIL WHERE TO_CHAR (CREATE_TIME, 'YYYY-MM-DD') IN
#{day}
) GROUP BY TO_CHAR (CREATE_TIME, 'YYYY-MM-DD') ORDER BY TO_CHAR (CREATE_TIME, 'YYYY-MM-DD')

SELECT SUM(TON) "ton", TO_CHAR (DATE_TIME, 'YYYY-MM') "month" FROM S_PORT_THROIGHPUT WHERE CARGO_TYPE = #{cargoType}
AND PORT_CODE = #{portCode}
AND DATE_TYPE = '2' AND TO_CHAR (DATE_TIME, 'YYYY-MM') IN
#{month}
GROUP BY TO_CHAR (DATE_TIME, 'YYYY-MM') ORDER BY TO_CHAR (DATE_TIME, 'YYYY-MM')

SELECT SUM(TON) "ton", TO_CHAR (DATE_TIME, 'YYYY-MM-DD') "day" FROM S_PORT_THROIGHPUT WHERE CARGO_TYPE = #{cargoType}
AND PORT_CODE = #{portCode}
AND DATE_TYPE = '3' AND TO_CHAR (DATE_TIME, 'YYYY-MM-DD') IN
#{day}
GROUP BY TO_CHAR (DATE_TIME, 'YYYY-MM-DD') ORDER BY TO_CHAR (DATE_TIME, 'YYYY-MM-DD')

SELECT SHIP_NAME "shipName", CARGO_NAME "cargoName", LOAD_OR_UNLOAD "loadOrUnload", TON "ton", SHIP_STATUS "shipStatus", BERTH_TIME "berthTime", BERTH_NAME "berthName", SCHEDULE "schedule" FROM S_SHIP_TRENDS WHERE SHIP_STATUS != '9'
AND PORT_CODE = #{portCode}
ORDER BY BERTH_TIME DESC

SELECT SHIP_NAME "shipName", CARGO_NAME "cargoName", LOAD_OR_UNLOAD "loadOrUnload", TON "ton", SHIP_STATUS "shipStatus", TO_CHAR (BERTH_TIME, 'YYYY-MM-DD HH24:MI') "berthTime", TO_CHAR (LEAVE_TIME, 'YYYY-MM-DD HH24:MI') "leaveTime", BERTH_NAME "berthName", SCHEDULE "schedule" FROM S_SHIP_TRENDS
PORT_CODE = #{portCode}
ORDER BY BERTH_TIME DESC

SELECT "SUM" (TON) "ton", CASE WHEN CARGO_TYPE = 1 THEN '件' WHEN CARGO_TYPE = 2 THEN '散' ELSE '其他' END AS "packingName" FROM S_PORT_STORAGE
PORT_CODE = #{portCode}
GROUP BY CARGO_TYPE

SELECT "SUM" (TON) "ton", CARGO_NAME "cargoName" FROM S_PORT_STORAGE
PORT_CODE = #{portCode}
HAVING "SUM" (TON) > 0 GROUP BY CARGO_NAME
